189	// synthesizeRunsFromBundles derives try-layer Run records from .ddx/executions/
190	// bundle directories. Each bundle = one execute-bead attempt (a "try" in the
191	// three-layer model). Run-layer records are synthesized separately from the
192	// AgentSession index, since multiple agent invocations may share a try.
193	func synthesizeRunsFromBundles(projectID, projectRoot string) []*ddxgraphql.Run {
194		dir := filepath.Join(projectRoot, agent.ExecuteBeadArtifactDir)
195		entries, err := os.ReadDir(dir)
196		if err != nil {
197			return nil
198		}
199		out := make([]*ddxgraphql.Run, 0, len(entries))
200		for _, entry := range entries {
201			if !entry.IsDir() {
202				continue
203			}
204			name := entry.Name()
205			if !looksLikeBundleID(name) {
206				continue
207			}
208			bundleDirAbs := filepath.Join(dir, name)
209			exec := loadExecutionBundle(projectID, projectRoot, bundleDirAbs, name)
210			if exec == nil {
211				continue
212			}
213			run := executionBundleToRun(name, exec)
214			out = append(out, run)
215		}
216		sort.Slice(out, func(i, j int) bool {
217			si, sj := "", ""
218			if out[i].StartedAt != nil {
219				si = *out[i].StartedAt
220			}
221			if out[j].StartedAt != nil {
222				sj = *out[j].StartedAt
223			}
224			return si > sj
225		})
226		return out
227	}
228	
229	// executionBundleToRun converts an Execution bundle to a try-layer Run record.
230	// Bundles correspond to one execute-bead attempt (a try): they carry
231	// base/result revisions, a verdict, and the bead under attempt. Per-invocation
232	// fields (harness, model, tokens) live on the run-layer records synthesized
233	// from AgentSession instead.
234	func executionBundleToRun(id string, exec *ddxgraphql.Execution) *ddxgraphql.Run {
235		status := "success"
236		if exec.Status != nil {
237			status = *exec.Status
238		} else if exec.Verdict != nil {
239			status = strings.ToLower(*exec.Verdict)
240		}
241	
242		run := &ddxgraphql.Run{
243			ID:          "exec-" + id,
244			Layer:       ddxgraphql.RunLayerTry,
245			Status:      status,
246			ChildRunIds: []string{},
247		}
248		if exec.StartedAt != nil {
249			run.StartedAt = exec.StartedAt
250		} else {
251			s := exec.CreatedAt
252			run.StartedAt = &s
253		}
254		if exec.FinishedAt != nil {
255			run.CompletedAt = exec.FinishedAt
256		}
257		if exec.BeadID != nil {
258			run.BeadID = exec.BeadID
259		}
260		if exec.BaseRev != nil {
261			run.BaseRevision = exec.BaseRev
262		}
263		if exec.ResultRev != nil {
264			run.ResultRevision = exec.ResultRev
265		}
266		if outcome := mergeOutcomeFromVerdict(exec); outcome != "" {
267			run.MergeOutcome = &outcome
268		}
269		run.EvidenceLinks = []string{exec.BundlePath}
270		return run
271	}
272	
273	// mergeOutcomeFromVerdict normalizes the bundle verdict/status into the
274	// {merged, preserved} space the try layer reports.
275	func mergeOutcomeFromVerdict(exec *ddxgraphql.Execution) string {
276		v := ""
277		if exec.Verdict != nil {
278			v = strings.ToLower(*exec.Verdict)
279		}
280		if v == "" && exec.Status != nil {
281			v = strings.ToLower(*exec.Status)
282		}
283		switch v {
284		case "preserved", "preserve":
285			return "preserved"
286		case "merged", "merge", "success", "pass":
287			if exec.ResultRev != nil && *exec.ResultRev != "" {
288				return "merged"
289			}
290			return ""
291		}
292		return ""
293	}
