295	// synthesizeRunsFromSessions derives run-layer Run records from the agent
296	// session index. Each AgentSession entry = one agent invocation (one "run"
297	// in the three-layer model). When the session points at a bundle directory,
298	// the resulting Run is parented to the matching try-layer record.
299	func synthesizeRunsFromSessions(projectID, projectRoot string) []*ddxgraphql.Run {
300		logDir := agent.SessionLogDirForWorkDir(projectRoot)
301		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{DefaultRecent: true})
302		if err != nil {
303			return nil
304		}
305		out := make([]*ddxgraphql.Run, 0, len(entries))
306		for _, e := range entries {
307			out = append(out, sessionEntryToRun(e))
308		}
309		return out
310	}
311	
312	// sessionEntryToRun projects one SessionIndexEntry onto a run-layer Run.
313	// AgentSession is the canonical backing store under layer=run; this projection
314	// is lossless against AgentSession: every field carried by the session index
315	// (harness, provider, model, tokens, cached tokens, cost, duration, status,
316	// billingMode, outcome, detail) is mapped onto the Run record. Heavy bodies
317	// (prompt/response/stderr) are still loaded only by run(id:) via loadRunDetail.
318	func sessionEntryToRun(e agent.SessionIndexEntry) *ddxgraphql.Run {
319		status := strings.ToLower(e.Outcome)
320		if status == "" {
321			if e.ExitCode == 0 {
322				status = "success"
323			} else {
324				status = "failure"
325			}
326		}
327		run := &ddxgraphql.Run{
328			ID:          e.ID,
329			Layer:       ddxgraphql.RunLayerRun,
330			Status:      status,
331			ChildRunIds: []string{},
332		}
333		if !e.StartedAt.IsZero() {
334			s := e.StartedAt.UTC().Format(time.RFC3339)
335			run.StartedAt = &s
336		}
337		if !e.EndedAt.IsZero() {
338			s := e.EndedAt.UTC().Format(time.RFC3339)
339			run.CompletedAt = &s
340		} else if !e.StartedAt.IsZero() && e.DurationMS > 0 {
341			s := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
342			run.CompletedAt = &s
343		}
344		if e.BeadID != "" {
345			bid := e.BeadID
346			run.BeadID = &bid
347		}
348		if e.Harness != "" {
349			h := e.Harness
350			run.Harness = &h
351		}
352		if e.Provider != "" {
353			p := e.Provider
354			run.Provider = &p
355		}
356		if e.Model != "" {
357			m := e.Model
358			run.Model = &m
359		}
360		if e.InputTokens > 0 {
361			v := e.InputTokens
362			run.TokensIn = &v
363		}
364		if e.OutputTokens > 0 {
365			v := e.OutputTokens
366			run.TokensOut = &v
367		}
368		if e.CachedTokens > 0 {
369			v := e.CachedTokens
370			run.CachedTokens = &v
371		}
372		if e.CostUSD != 0 {
373			c := e.CostUSD
374			run.CostUsd = &c
375		}
376		if e.DurationMS > 0 {
377			d := e.DurationMS
378			run.DurationMs = &d
379		}
380		// Lossless join with AgentSession: project session-only fields onto Run so
381		// run-layer queries don't lose data that lives only on AgentSession.
382		if e.BillingMode != "" {
383			bm := e.BillingMode
384			run.BillingMode = &bm
385		}
386		if e.Outcome != "" {
387			oc := e.Outcome
388			run.Outcome = &oc
389		}
390		if e.Detail != "" {
391			d := e.Detail
392			run.Detail = &d
393		}
394		var evidence []string
395		if e.BundlePath != "" {
396			evidence = append(evidence, filepath.ToSlash(e.BundlePath))
397			if parent := parentTryIDFromBundlePath(e.BundlePath); parent != "" {
398				run.ParentRunID = &parent
399			}
400		}
401		if e.NativeLogRef != "" {
402			evidence = append(evidence, filepath.ToSlash(e.NativeLogRef))
403		}
404		if len(evidence) > 0 {
405			run.EvidenceLinks = evidence
406		}
407		return run
408	}
