430	// GetRunsGraphQL implements RunsStateProvider.
431	func (s *ServerState) GetRunsGraphQL(projectID string, filter ddxgraphql.RunFilter) []*ddxgraphql.Run {
432		var all []*ddxgraphql.Run
433	
434		if projectID != "" {
435			proj, ok := s.GetProjectByID(projectID)
436			if !ok {
437				return nil
438			}
439			all = s.loadRunsForProject(projectID, proj.Path)
440		} else {
441			for _, proj := range s.GetProjects(false) {
442				all = append(all, s.loadRunsForProject(proj.ID, proj.Path)...)
443			}
444			sort.Slice(all, func(i, j int) bool {
445				si, sj := "", ""
446				if all[i].StartedAt != nil {
447					si = *all[i].StartedAt
448				}
449				if all[j].StartedAt != nil {
450					sj = *all[j].StartedAt
451				}
452				return si > sj
453			})
454		}
455		return ddxgraphql.ApplyRunFilter(all, filter)
456	}
