112	// BeadUpdate is the resolver for the beadUpdate mutation.
113	func (r *mutationResolver) BeadUpdate(ctx context.Context, id string, input BeadUpdateInput) (*Bead, error) {
114		if r.workingDir(ctx) == "" {
115			return nil, fmt.Errorf("working directory not configured")
